mapper.insert:
INSERT INTO image_recognition (
    user_id, image_url, recognition_result, recognition_model, recognition_time, status, error_msg
) VALUES (
    #{userId}, #{imageUrl}, #{recognitionResult}, #{recognitionModel}, #{recognitionTime}, #{status}, #{errorMsg}
)

mapper.select:
SELECT
    id, user_id AS userId, image_url AS imageUrl, recognition_result AS recognitionResult,
    recognition_model AS recognitionModel, recognition_time AS recognitionTime, status, error_msg AS errorMsg
FROM image_recognition
WHERE user_id = #{userId}

    AND recognition_time >= #{startTime}


    AND recognition_time <= #{endTime}

ORDER BY recognition_time DESC

mapper.update:
UPDATE image_recognition
SET
    status = #{status},
    error_msg = #{errorMsg}
WHERE id = #{id}
